from flask import Flask, request, jsonify, session
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import random
import pyotp

app = Flask(__name__)
app.secret_key = 'your_secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(128), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(16), nullable=True)

db.create_all()

@app.route('/api/register', methods=['POST'])
def register():
    data = request.json
    new_user = User(username=data['username'], password=generate_password_hash(data['password']))
    db.session.add(new_user)
    db.session.commit()
    return jsonify({'message': 'User registered successfully'}), 201

@app.route('/api/login', methods=['POST'])
def login():
    data = request.json
    user = User.query.filter_by(username=data['username']).first()
    if user and check_password_hash(user.password, data['password']):
        session['user_id'] = user.id
        if user.mfa_enabled:
            return jsonify({'mfa_required': True, 'mfa_secret': user.mfa_secret}), 200
        return jsonify({'message': 'Access granted'}), 200
    return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/api/verify-otp', methods=['POST'])
def verify_otp():
    data = request.json
    user = User.query.get(session['user_id'])
    if user and pyotp.TOTP(user.mfa_secret).verify(data['otp']):
        return jsonify({'message': 'Access granted'}), 200
    return jsonify({'message': 'Invalid OTP'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.json
    user = User.query.filter_by(username=data['username']).first()
    if user and check_password_hash(user.password, data['password']):
        return jsonify({'message': 'Access granted without MFA'}), 200
    return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)